import logo from './logo.svg';
import './App.css';
import TodoItems from './components/TodoItems'
import FilterTasks from './components/FilterTasks';
import { useState, useEffect } from 'react';

function App() {

const[tasks, setTask] = useState([])


const url = 'https://todo-app-7ea63-default-rtdb.europe-west1.firebasedatabase.app/tasks/.json';


useEffect(()=>{
  fetch(url)
  .then(res=> res.json())
  .then(result=>{
let taskArr = []
    for(const key in result){
      taskArr.push({
        id:key,
        name:result[key].name,
        description:result[key].description,
        isDone:result[key].isDone,
        isImportant:result[key].isImportant
      })
    }
    setTask(taskArr)
  })
},[])




  return (
    <main className="App">
      <FilterTasks />
      <TodoItems task={tasks} />
    </main>
  );
}

export default App;
